import { Box, Button, Checkbox, FormControlLabel, FormGroup, Modal, Typography } from '@mui/material';
import React from 'react';
import { Genre } from '../home-page/movies-grid';

const mockGenres: Array<Genre> = [
	{
		id: 28,
		name: 'Action'
	},
	{
		id: 12,
		name: 'Adventure'
	},
	{
		id: 16,
		name: 'Animation'
	},
	{
		id: 35,
		name: 'Comedy'
	},
	{
		id: 80,
		name: 'Crime'
	},
	{
		id: 99,
		name: 'Documentary'
	},
	{
		id: 18,
		name: 'Drama'
	},
	{
		id: 10751,
		name: 'Family'
	},
	{
		id: 14,
		name: 'Fantasy'
	},
	{
		id: 36,
		name: 'History'
	},
	{
		id: 27,
		name: 'Horror'
	},
	{
		id: 10402,
		name: 'Music'
	},
	{
		id: 9648,
		name: 'Mystery'
	},
	{
		id: 10749,
		name: 'Romance'
	},
	{
		id: 878,
		name: 'Science Fiction'
	},
	{
		id: 10770,
		name: 'TV Movie'
	},
	{
		id: 53,
		name: 'Thriller'
	},
	{
		id: 10752,
		name: 'War'
	},
	{
		id: 37,
		name: 'Western'
	}
];

const style = {
	position: 'absolute' as const,
	top: '50%',
	left: '50%',
	transform: 'translate(-50%, -50%)',
	width: 800,
	height: 600,
	bgcolor: 'background.paper',
	border: '2px solid #000',
	boxShadow: 24,
	p: 4
};
export default function StartModal() {
	const [open, setOpen] = React.useState(true);
	const handleOpen = () => setOpen(true);
	const handleClose = () => setOpen(false);

	function getGenresOptions(genre: number) {
		const genreTitle: Array<Genre> = mockGenres.filter((g: any) => g.id === genre);

		return <FormControlLabel control={<Checkbox />} label={`${genreTitle[0].name}`} />;
	}

	return (
		<div>
			<Modal open={open} onClose={handleClose} aria-labelledby="modal-modal-title" aria-describedby="modal-modal-description">
				<Box sx={style}>
					<Typography id="modal-modal-title" variant="h6" component="h2">
						Selecione suas preferências
					</Typography>
					<Typography id="modal-modal-description" sx={{ mt: 2 }}>
						Selecione no mínimo 3 e no máximo 5 opções de Gênero.
						<FormGroup>
							<div className="flex justify-center p-6 bg-blue-600">
								<FormControlLabel control={<Checkbox />} label="Animation" />
								<FormControlLabel control={<Checkbox />} label="Horror" />
								<FormControlLabel control={<Checkbox />} label="Comedy" />
							</div>
						</FormGroup>
					</Typography>
				</Box>
			</Modal>
		</div>
	);
}
